export * as RadioGroup from "./namespace";
export * from "./radio-group";
export * from "./styles";

"use client";

import { CircleIcon } from "lucide-react";
import {
  composeRenderProps,
  RadioGroup as RACRadioGroup,
  Radio,
} from "react-aria-components";
import { RadioGroupStyles } from "./styles";

export interface RadioGroupRootProps
  extends React.ComponentProps<typeof RACRadioGroup> {}

export function RadioGroupRoot({ className, ...props }: RadioGroupRootProps) {
  return (
    <RACRadioGroup
      className={composeRenderProps(className, (className) =>
        RadioGroupStyles.Root({ className })
      )}
      data-slot="radio-group-root"
      {...props}
    />
  );
}

export interface RadioGroupItemProps
  extends React.ComponentProps<typeof Radio> {}

export function RadioGroupItem({ className, ...props }: RadioGroupItemProps) {
  return (
    <Radio
      className={composeRenderProps(className, (className) =>
        RadioGroupStyles.Item({ className })
      )}
      data-slot="radio-group-item"
      {...props}
    />
  );
}

export interface RadioGroupIndicatorProps
  extends Omit<React.ComponentProps<"span">, "children"> {}

export function RadioGroupIndicator({
  className,
  ...props
}: RadioGroupIndicatorProps) {
  return (
    <span
      {...props}
      aria-hidden="true"
      className={RadioGroupStyles.Indicator({ className })}
      data-slot="radio-group-indicator"
    >
      <CircleIcon className="size-2 fill-primary opacity-0 transition group-selected:opacity-100" />
    </span>
  );
}

import { compose, cva } from "~/registry/lib/cva";
import { LabelStyles } from "../label";

export const RadioGroupStyles = {
  Indicator: cva({
    base: [
      "grid aspect-square size-4 shrink-0 place-content-center rounded-full border border-input text-primary",
      "shadow-xs outline-none transition",
      "group-focus-visible:border-ring group-focus-visible:ring-[3px] group-focus-visible:ring-ring/50",
      "group-disabled:cursor-not-allowed group-disabled:opacity-50",
      "group-aria-invalid:border-destructive group-aria-invalid:ring-destructive/20",
      "group-dark:bg-input/30 group-dark:aria-invalid:ring-destructive/40",
    ],
  }),
  Item: compose(
    LabelStyles,
    cva({
      base: ["group flex w-fit items-center gap-3"],
    })
  ),
  Root: cva({
    base: ["grid gap-3"],
  }),
};

export {
  RadioGroupIndicator as Indicator,
  RadioGroupItem as Item,
  RadioGroupRoot as Root,
} from "./radio-group";
